import { gql } from '@apollo/client';

export const queryMainPage = gql`
  query MainPage($locale: String!, $limit: Int) {
    headerBanners(locale: $locale) {
      banners {
        title
        subtitle
        image {
          url
          name
        }
        buttonLink
        buttonTitle
      }
    }
    headerButtons(locale: $locale) {
      buttons {
        title
        link
      }
    }
    footerSections(locale: $locale) {
      sections {
        title
        links {
          title
          link
          image {
            url
            name
          }
        }
      }
    }
    headerLinks(locale: $locale) {
      links {
        title
        link
      }
    }
    homePageSpecialSection(locale: $locale) {
      title
      interactiveCard {
        title
        description
        link
        buttonText
      }
    }
  }
`;
